import React, { useEffect, useState } from "react";
import { Box, Image, Text } from "@chakra-ui/react";
import Slider from "react-slick";
import "slick-carousel/slick/slick.css";
import "slick-carousel/slick/slick-theme.css";
import "../../Pages/LandingPageComponents/LandingPageComponent.css";
import Card from "../../Pages/LandingPageComponents/Card";
import LoadingComponent from "../../Pages/LoadingComponents/LoadingComponent";
import axios from "axios";

const InProgressCarousel = () => {
  const [loading, setLoading] = useState(true);
  const [course, setCourse] = useState([]);

  const settings = {
    swipe: true,
    dots: false,
    infinite: false,
    speed: 500,
    slidesToShow: 4,
    slidesToScroll: 1,
    responsive: [
      { breakpoint: 1200, settings: { slidesToShow: 4 } },
      { breakpoint: 1024, settings: { slidesToShow: 3 } },
      { breakpoint: 800, settings: { slidesToShow: 2 } },
      { breakpoint: 500, settings: { slidesToShow: 1 } },
    ],
  };

  useEffect(() => {
    const user = JSON.parse(localStorage.getItem("user"));

    axios
      .get(
        `https://elearning-platform-using-mern-j5py.vercel.app/users/userCourse/${user.userId}`
      )
      .then((res) => {
        setCourse(res.data.course);
        setLoading(false);
      })
      .catch((err) => {
        console.log(err);
        setLoading(false);
      });
  }, []);

  // 🔥 Loading state
  if (loading) {
    return (
      <Box py={6}>
        <LoadingComponent />
      </Box>
    );
  }

  // 🔥 Empty state
  if (course.length === 0) {
    return (
      <Box
        textAlign="center"
        py={10}
        bg="#f7f9fa"
        borderRadius="12px"
      >
        <Image
          mx="auto"
          w={{ base: "70%", md: "40%", lg: "25%" }}
          src="https://cdn.dribbble.com/users/1693462/screenshots/3504905/media/6d5a0df598037bf7a872f1f8aef118b8.gif"
          alt="empty"
        />
        <Text mt={4} fontWeight="bold" color="#1c1d1f">
          You haven't enrolled in any courses yet
        </Text>
      </Box>
    );
  }

  // 🔥 Main carousel
  return (
    <Box py={2}>
      <Slider {...settings}>
        {course.map((el) => (
          <Box px={2} key={el._id}>
            <Card {...el} />
          </Box>
        ))}
      </Slider>
    </Box>
  );
};

export default InProgressCarousel;
